// Combinar estadísticas con alertas
const stats = $('PostgreSQL — Estadísticas del día').first().json;
const alertas = $('PostgreSQL — Top 5 alertas activas').all().map(i => i.json);

const colorSeveridad = {
  critica: '#ef4444',
  alta: '#f97316',
  media: '#f59e0b',
  baja: '#3b82f6'
};

const htmlAlertas = alertas.length === 0
  ? '<p style="color:#4ade80;text-align:center;padding:16px">✅ Sin alertas activas</p>'
  : alertas.map(a => `
    <tr>
      <td style="padding:8px;border-bottom:1px solid #1e293b">
        <span style="background:${colorSeveridad[a.severidad] || '#64748b'}22;color:${colorSeveridad[a.severidad] || '#64748b'};padding:2px 8px;border-radius:12px;font-size:11px;font-weight:bold">
          ${a.severidad.toUpperCase()}
        </span>
       </td>
      <td style="padding:8px;border-bottom:1px solid #1e293b;color:#94a3b8">${a.lote_nombre}</td>
      <td style="padding:8px;border-bottom:1px solid #1e293b;font-size:12px">${a.mensaje}</td>
      <td style="padding:8px;border-bottom:1px solid #1e293b;color:#64748b;font-size:11px">${a.hora}</td>
     </tr>`).join('');

const estadoSistema = parseInt(stats.alertas_criticas) > 0
  ? { emoji: '🔴', texto: 'ATENCIÓN REQUERIDA', color: '#ef4444' }
  : parseInt(stats.alertas_activas) > 0
  ? { emoji: '🟡', texto: 'MONITOREAR', color: '#f59e0b' }
  : { emoji: '🟢', texto: 'NORMAL', color: '#4ade80' };

// --- Generar bloque de confianza condicional ---
let htmlConfianza = '';
if (stats.confianza_prediccion && stats.confianza_prediccion !== 'null') {
  htmlConfianza = `<div style="font-size: 12px; margin-top: 8px;">Confianza: ${stats.confianza_prediccion}%</div>`;
}

return [{
  json: {
    ...stats,
    html_alertas: htmlAlertas,
    estado_sistema: estadoSistema,
    fecha_hoy: new Date().toLocaleDateString('es-PE', {weekday:'long', year:'numeric', month:'long', day:'numeric'}),
    hora_generacion: new Date().toLocaleTimeString('es-PE'),
    html_confianza: htmlConfianza   // ← NUEVA variable
  }
}];

