=<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Reporte Diario - AgriFlow</title>
  <style>
    @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;600;800&display=swap');
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
      background-color: #f8fafc;
      margin: 0;
      padding: 40px 20px;
      color: #020617;
    }
    .container {
      max-width: 680px;
      margin: 0 auto;
      background: #ffffff;
      border-radius: 32px;
      overflow: hidden;
      box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.08);
      border: 1px solid #e2e8f0;
    }
    .header {
      background: linear-gradient(135deg, #020617 0%, #1e293b 100%);
      padding: 36px 32px;
      text-align: center;
    }
    .header h1 {
      font-size: 28px;
      font-weight: 800;
      margin: 0;
      color: #ffffff;
      letter-spacing: -1px;
    }
    .header p {
      font-size: 12px;
      margin-top: 8px;
      text-transform: uppercase;
      letter-spacing: 2px;
      color: #10b981;
      font-weight: 700;
    }
    .content {
      padding: 40px 32px;
    }
    .saludo {
      font-size: 16px;
      font-weight: 600;
      margin-bottom: 4px;
    }
    .subtitulo {
      color: #475569;
      margin-bottom: 24px;
      font-size: 14px;
    }
    .stats-grid {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 16px;
      margin-bottom: 32px;
    }
    .stat-card {
      background: #f8fafc;
      border-radius: 20px;
      padding: 20px 16px;
      text-align: center;
      transition: transform 0.1s ease;
      border: 1px solid #eef2ff;
    }
    .stat-value {
      font-size: 32px;
      font-weight: 800;
      color: #0f172a;
      line-height: 1.2;
    }
    .stat-label {
      font-size: 11px;
      font-weight: 600;
      color: #64748b;
      text-transform: uppercase;
      margin-top: 8px;
      letter-spacing: 0.5px;
    }
    .stat-unit {
      font-size: 10px;
      color: #94a3b8;
    }
    .prediction-card {
      background: #f0fdf4;
      border: 1px solid #bbf7d0;
      border-radius: 20px;
      padding: 20px;
      margin: 20px 0;
      text-align: center;
    }
    .prediction-card h3 {
      font-size: 14px;
      font-weight: 700;
      color: #15803d;
      margin-bottom: 8px;
    }
    .prediction-value {
      font-size: 28px;
      font-weight: 800;
      color: #16a34a;
    }
    .alertas-table {
      width: 100%;
      border-collapse: collapse;
      margin: 20px 0 10px;
      font-size: 13px;
    }
    .alertas-table th {
      text-align: left;
      padding: 12px 8px;
      background: #f1f5f9;
      color: #334155;
      font-weight: 600;
      border-bottom: 2px solid #e2e8f0;
    }
    .alertas-table td {
      padding: 12px 8px;
      border-bottom: 1px solid #eef2f6;
      color: #475569;
    }
    .severity-badge {
      display: inline-block;
      padding: 4px 10px;
      border-radius: 40px;
      font-size: 10px;
      font-weight: 700;
    }
    .button-group {
      display: flex;
      justify-content: center;
      gap: 16px;
      flex-wrap: wrap;
      margin: 32px 0 16px;
    }
    .btn {
      padding: 12px 24px;
      border-radius: 40px;
      text-decoration: none;
      font-weight: 600;
      font-size: 13px;
      display: inline-block;
      transition: 0.2s;
    }
    .btn-primary {
      background: #020617;
      color: white;
      border: 1px solid #1e293b;
    }
    .btn-warning {
      background: #ef4444;
      color: white;
    }
    .btn-success {
      background: #10b981;
      color: white;
    }
    .footer {
      background: #f8fafc;
      padding: 24px;
      text-align: center;
      font-size: 11px;
      color: #64748b;
      border-top: 1px solid #e2e8f0;
      margin-top: 10px;
    }
    @media (max-width: 560px) {
      .stats-grid {
        grid-template-columns: 1fr;
        gap: 12px;
      }
      .content {
        padding: 24px 20px;
      }
    }
  </style>
</head>
<body>
<div class="container">
  <div class="header">
    <h1>📊 Reporte Diario</h1>
    <p>AgriFlow · Agricultura de Precisión</p>
  </div>
  <div class="content">
    <p class="saludo">Buenos días, <strong>{{ $json.nombre_usuario }}</strong> 👋</p>
    <p class="subtitulo">Resumen operativo de <strong>{{ $json.nombre_finca }}</strong> — {{ $json.fecha_hoy }}</p>

    <!-- KPIs principales -->
    <div class="stats-grid">
      <div class="stat-card">
        <div class="stat-value">{{ $json.lecturas_24h || 0 }}</div>
        <div class="stat-label">📡 Lecturas 24h</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">{{ $json.anomalias_24h || 0 }}</div>
        <div class="stat-label">🔍 Anomalías</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">{{ $json.alertas_activas || 0 }}</div>
        <div class="stat-label">⚠️ Alertas activas</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">{{ $json.riegos_completados || 0 }}</div>
        <div class="stat-label">💧 Riegos completados</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">{{ $json.temporadas_activas || 0 }}</div>
        <div class="stat-label">🌱 Temporadas activas</div>
      </div>
      <div class="stat-card">
        <div class="stat-value">{{ $json.lamina_promedio_mm || '—' }} <span class="stat-unit">mm</span></div>
        <div class="stat-label">💧 Lámina promedio</div>
      </div>
    </div>

    <!-- Predicción ML (bloque completo, con confianza condicional) -->
    <div class="prediction-card">
      <h3>🤖 Predicción de rendimiento (última)</h3>
      <div class="prediction-value">{{ $json.ultima_prediccion || 'No disponible' }} kg/ha</div>
      {{ $json.html_confianza }}
    </div>

    <!-- Tabla de alertas activas (top 5) -->
    <h3 style="font-size: 15px; font-weight: 700; margin: 24px 0 12px;">⚠️ Alertas activas (prioritarias)</h3>
    <table class="alertas-table">
      <thead>
        <tr><th>Severidad</th><th>Lote</th><th>Mensaje</th><th>Hora</th></tr>
      </thead>
      <tbody>
        {{ $json.html_alertas }}
      </tbody>
    </table>
  </div>
  <div class="footer">
    <p>Reporte automático generado el {{ $json.fecha_hoy }} a las {{ $json.hora_generacion }}</p>
    <p>© 2026 AgriFlow · La Libertad, Perú</p>
  </div>
</div>
</body>
</html>
